import boto3
from botocore.exceptions import ClientError
import json

# Initialize the AWS SQS client
sqs = boto3.client('sqs')

def publish_to_sqs(queue_url, user_data):
    """
    Publish a message to an SQS queue.
    
    Args:
        queue_url (str): The URL of the SQS queue.
        user_data (dict): A dictionary containing user data with PII information.

    Returns:
        str: The response from the SQS service after publishing the message.
    """

    try:
        # Create a new message to send
        message = json.dumps(user_data)

        # Publish a message to the queue
        response = sqs.send_message(
            QueueUrl=queue_url,
            MessageBody=message
        )

        print(f"Message sent. Message ID: {response['MessageId']}")
        
    except ClientError as e:
        print(e)
        
# Example usage    
user_data = {
    "email": "test@example.com",
    "phone_number": "+1234567890",
    "address": "123 Main St"
}

publish_to_sqs('https://sqs.us-east-1.amazonaws.com/your-account-id/your-queue-name', user_data)